// Parse AI Agent output (raw JSON or inside a markdown code fence),
// merge with context from Read Incident Context and SetVars,
// and build a Jira payload including a Mattermost permalink to the source message.

const raw = $input.first().json.output ?? '';
const ctx = $('ReadIncidentContext').first().json;
const vars = $('SetVars').first().json;

// Strip surrounding markdown code fences if present
const cleaned = String(raw)
  .replace(/^\s*```(?:json)?\s*/i, '')
  .replace(/\s*```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error(`Failed to parse AI Agent output as JSON: ${err.message}. Raw output was: ${raw}`);
}

// Build a Mattermost permalink to the thread where the request was posted
const mattermostBase = (vars.MATTERMOST_URL || '').replace(/\/+$/, '');
const threadLink = ctx.post_id ? `${mattermostBase}/${ctx.post_id}` : null;

// Compose source block appended to the Jira description
const sourceLines = [
  '',
  '---',
  `*Source:* @${ctx.user_name || 'unknown'} in channel #${ctx.channel_name || 'unknown'}`,
];
if (threadLink) sourceLines.push(`*Message link:* ${threadLink}`);
if (ctx.summary) sourceLines.push(`*Classification:* ${ctx.summary} (confidence: ${ctx.confidence ?? 'n/a'})`);

const description = `${parsed.description || ''}\n${sourceLines.join('\n')}`;

return [{
  json: {
    summary: parsed.summary || '(no summary)',
    description,
    label: parsed.label || 'Operations',
    user_name: ctx.user_name,
    on_call_user: ctx.on_call_user,
    channel_id: ctx.channel_id,
    post_id: ctx.post_id,
    thread_link: threadLink,
    agent_raw_output: raw,
  },
}];

// Read the classification object passed from the parent classifier workflow.
// Available fields: message, post_id, channel_id, user_name,
// channel_name, category, confidence, summary, on_call_user.

const data = $input.first().json;

console.log(`Task received: ${data.summary}`);
console.log(`From: ${data.user_name} in #${data.channel_name}`);
console.log(`Confidence: ${data.confidence}`);

return [{ json: data }];
